<template>
    <v-container fluid class="pa-6 pt-4 fill-height cctv-roi-manage">
      <v-row no-gutters class="fill-height">
        <v-sheet width="100%" height="33">
          <h3 class="font-weight-bold">{{ title }}</h3>
        </v-sheet>
        <v-sheet width="100%" height="calc(100% - 32px)" class="pt-2 overflow-hidden cctv-roi-manage-contents">
          <v-row no-gutters class="pa-0 fill-height">
            <v-card width="170" color="login_bg" class="pa-2 fill-height red">
              <v-list nav dense style="max-height: 1116px;
                                      overflow-y: auto;
                                      background: #eef2f5;">
                <v-list-item-group v-model="selected" color="primary" class="login_bg">
                  <template v-for="(item, i) in list">
                    <v-list-item :key="item.cctv_id" :disabled="item.cctv_id == selected" :input-value="item.cctv_id" :value="item.cctv_id" class="login_bg" @click="onCCTV(item)">
                      <v-list-item-content>
                        <v-list-item-title v-text="`${item.camera_nm}(${item.camera_desc})`" class="text-subtitle-2" />
                      </v-list-item-content>
                    </v-list-item>
                  </template>
                </v-list-item-group>
              </v-list>
            </v-card>
            <v-col class="ml-4 fill-height overflow-x-hidden overflow-y-auto">
              <v-card width="100%" height="100%" outlined rounded="md" class="pa-3 px-5">
                <v-sheet height="33" style="margin-bottom: 15px;margin-top: -10px;">
                  <v-row >
                    <v-col cols="2"><h3 class="font-weight-bold">{{ `${selectedItem.cctv_id}` }}</h3></v-col>
                    <v-col style="margin-top: -10px;">
                      <v-row>
                       
                          <h4 style="margin-top: 10px;" class="font-weight-bold secondary--text">{{ $t('setGridMode') }}</h4>
                 
                        <v-col cols="4" style="margin-top: -10px;">
                          <v-card  style="overflow: hidden !important;" width="100%" outlined height="calc(100% - 8px)" class="mt-1 pa-2 overflow-y-auto text-left">
                            <v-radio-group 
                            style="margin-top: -3px;"
                            v-model="setMode"
                            :disabled="false"
                            @change="handleSetMode"
                            mandatory
                            row>
                              <template v-for="(button, index) in setModeButton">
                                <v-radio
                                  :key="`${button.id}_btn`"
                                  :label="$t(button.text)"
                                  :value="button.id"
                                  >
                                </v-radio>
                              </template>
                            </v-radio-group>
                          </v-card>
                        </v-col>
                      </v-row>
                      
                    </v-col>
                  </v-row>
                  
                </v-sheet>
                <v-sheet height="35" class="d-flex align-center">
                  <template v-if="setMode==0">
                    <template v-for="button in manualControlButtonFirst">
                      <v-btn
                        :key="button.id"
                        height="30"
                        color="btn_bg"
                        class="mr-2 px-0"
                        elevation="0"
                        outlined
                        rounded
                        :disabled="button.isDisable()"
                        small
                        :width="button.text ? 120 : 35"
                        @click="button.onClick"
                      >
                        <div class="font-weight-bold" :class="[button.isDisable() ? 'gray--text' : 'content--text']">
                          <v-icon size="14">{{ button.icon }}</v-icon>
                          <template v-if="button.text">
                            <span class="ml-1">{{ $t(button.text) }}</span>
                          </template>
                        </div>
                      </v-btn>
                    </template>
                  </template>
                  <template v-else>
                    <div style="display: flex; margin-right: 8rem;">
                      <template v-for="button in autoControlButtonFirst">
                        <v-btn
                          :key="button.id"
                          height="30"
                          color="btn_bg"
                          class="mr-2 px-0"
                          elevation="0"
                          outlined
                          rounded
                          :disabled="button.isDisable()"
                          small
                          :width="button.text ? 120 : 35"
                          @click="button.onClick"
                        >
                          <div class="font-weight-bold" :class="[button.isDisable() ? 'gray--text' : 'content--text']">
                            <v-icon size="14">{{ button.icon }}</v-icon>
                            <template v-if="button.text">
                              <span class="ml-1">{{ $t(button.text) }}</span>
                            </template>
                          </div>
                        </v-btn>
                      </template>
                    </div>
                    <div >
                      <template v-for="button in autoControlButtonFirst1">
                        <v-btn
                          :key="button.id"
                          height="30"
                          color="btn_bg"
                          class="mr-2 px-0"
                          elevation="0"
                          outlined
                          rounded
                          :disabled="button.isDisable()"
                          small
                          :width="button.text ? 120 : 35"
                          @click="button.onClick"
                        >
                          <div class="font-weight-bold" :class="[button.isDisable() ? 'gray--text' : 'content--text']">
                            <v-icon size="14">{{ button.icon }}</v-icon>
                            <template v-if="button.text">
                              <span class="ml-1">{{ $t(button.text) }}</span>
                            </template>
                          </div>
                        </v-btn>
                      </template>
                    </div>
                    
                  </template>
                </v-sheet>
                <v-sheet height="35" class="d-flex align-center">
                  <template v-if="setMode==0">
                    <template v-for="button in manualControlButtonSecond">
                      <v-btn
                        :key="button.id"
                        height="30"
                        color="btn_bg"
                        class="mr-2 px-0"
                        elevation="0"
                        outlined
                        rounded
                        :disabled="button.isDisable()"
                        small
                        :width="button.text ? 120 : 35"
                        @click="button.onClick"
                      >
                        <div class="font-weight-bold" :class="[button.isDisable() ? 'gray--text' : 'content--text']">
                          <v-icon size="14">{{ button.icon }}</v-icon>
                          <template v-if="button.text">
                            <span class="ml-1">{{ $t(button.text) }}</span>
                          </template>
                        </div>
                      </v-btn>
                    </template>
                  </template>
                  <template v-else>
                    <div style="display: flex;">
                      <template v-for="button in autoControlButtonSecond">
                        <v-btn
                          :key="button.id"
                          height="30"
                          color="btn_bg"
                          class="mr-2 px-0"
                          elevation="0"
                          outlined
                          rounded
                          :disabled="button.isDisable()"
                          small
                          :width="button.text ? 120 : 35"
                          @click="button.onClick"
                        >
                          <div class="font-weight-bold" :class="[button.isDisable() ? 'gray--text' : 'content--text']">
                            <v-icon size="14">{{ button.icon }}</v-icon>
                            <template v-if="button.text">
                              <span class="ml-1">{{ $t(button.text) }}</span>
                            </template>
                          </div>
                        </v-btn>
                      </template>
                    </div>
                    <div style="display: flex;">
                      <template v-for="button in autoControlButtonSecond1">
                        <v-btn
                          :key="button.id"
                          height="30"
                          color="btn_bg"
                          class="mr-2 px-0"
                          elevation="0"
                          outlined
                          rounded
                          :disabled="button.isDisable()"
                          small
                          :width="button.text ? 120 : 35"
                          @click="button.onClick"
                        >
                          <div class="font-weight-bold" :class="[button.isDisable() ? 'gray--text' : 'content--text']">
                            <v-icon size="14">{{ button.icon }}</v-icon>
                            <template v-if="button.text">
                              <span class="ml-1">{{ $t(button.text) }}</span>
                            </template>
                          </div>
                        </v-btn>
                      </template>
                    </div>
                  </template>
                  <v-spacer />
                  <v-tooltip top>
                    <template #activator="{ on, attrs }">
                      <v-btn
                        icon
                        v-bind="attrs"
                        v-on="on"
                      >
                        <svg-icon width="20" height="20" icon-class="help" color="#e6e6e6" />
                      </v-btn>
                    </template>
                    <span>{{ `Ctrl + 휠` }}</span>
                  </v-tooltip>
                  <template v-for="(button, index) in scaleButton">
                    <v-btn
                      :key="`${button.id}_btn`"
                      height="30"
                      color="btn_bg"
                      class="mr-2 px-0"
                      elevation="0"
                      outlined
                      rounded
                      :disabled="button.isDisable()"
                      small
                      :width="button.text ? 84 : 35"
                      @click="button.onClick"
                    >
                      <div class="font-weight-bold" :class="[button.isDisable() ? 'gray--text' : 'content--text']">
                        <v-icon size="14">{{ button.icon }}</v-icon>
                        <template v-if="button.text">
                          <span class="ml-1">{{ $t(button.text) }}</span>
                        </template>
                      </div>
                    </v-btn>
                    <template v-if="index == 0">
                      <v-sheet width="50" class="ml-2 mr-4 text-center" :key="index">
                        <span>{{ `${scaleFactor * 10}%` }}</span>
                      </v-sheet>
                    </template>
                  </template>
                  <v-sheet width="416" />
                </v-sheet>
                <v-sheet width="100%" min-width="700" height="calc(100% - 33px - 70px)" class="pt-1" ref="roiContainer">
                  <template v-if="isLoading">
                    <v-row no-gutters class="align-center justify-center fill-height">
                      <v-progress-circular indeterminate color="secondary" />
                    </v-row>
                  </template>
                  <template v-else>
                    <v-row no-gutters class="fill-height">
                      <v-col
                        class="pa-0 cctv-roi-manage-contents-image"
                        @mouseenter="onMouseEnter"
                        @mouseleave="onMouseLeave"
                        @wheel="onWheel"
                        ref="roiImage"
                      >
                        <v-sheet :width="scaleWidth/(scaleFactor / 0.1)" :height="scaleHeight/(scaleFactor / 0.1)" 
                          :style="`aspect-ratio: ${imageRatio}; transform: scale(${scaleFactor * 0.1}) !important;`">
                          <v-stage
                            :config="configKonva"
                            @click="onHandleClick"
                            @mouseenter="handleMouseEnter"
                            @mouseleave="handleMouseLeave"
                          >
                            <v-layer ref="layer">
                              <v-image
                                :config="{
                                  image: cctvImg,
                                  width: scaleWidth,
                                  height: scaleHeight,
                                  x: 0,
                                  y: 0,
                                }"
                                :style="`aspect-ratio: ${imageRatio};`"
                              />
                            </v-layer>
                          </v-stage>
                        </v-sheet>
                      </v-col>
                      <v-divider vertical class="mx-2" />
                      <v-sheet width="300" class="d-flex flex-column">
                        <v-col class="text-center overflow-hidden py-1" style="min-height: 190px;">
                          <h4 class="font-weight-bold secondary--text">{{ $t('standardGridCoord') }}</h4>
                          <v-card width="100%" outlined height="calc(100% - 35px)" class="mt-1 pa-2 overflow-y-auto text-left">
                            <v-radio-group 
                              v-model="sortDirection"
                              :disabled="standardGridCoordIsDisable || (this.selectedItem.initial_coordinates.length > 1 && !setGridOnOffmode)"
                              @change="handleStandardGrid"
                              mandatory>
                              <template v-for="(button, index) in sortDirectionButton">
                                <v-radio
                                  :key="`${button.id}_btn`"
                                  :label="$t(button.text)"
                                  :value="button.id"
                                  >
                                </v-radio>
                              </template>
                            </v-radio-group>
                          </v-card>
                        </v-col>
                        <v-col class="text-center overflow-hidden py-1">
                          <h4 class="font-weight-bold secondary--text">{{ $t('gridUnitSetting') }}</h4>
                          <v-card width="100%" outlined height="calc(100% - 35px)" class="mt-1 pa-2 overflow-y-auto text-left">
                            <v-radio-group 
                              v-model="gridUnit"
                              @change="handleGridUnit"
                              mandatory>
                              <v-radio
                                v-for="(button, index) in gridUnitButton"
                                :key="`${button.id}_btn`"
                                :label="$t(button.text)"
                                :value="button.id"
                                >
                              </v-radio>
                            </v-radio-group>
                          </v-card>
                        </v-col>
                        <v-col class="text-center py-1">
                          <!-- <h4 class="font-weight-bold secondary--text">{{ $t('refGridDetectonSetting') }}</h4> -->
                          <v-sheet width="100%" height="calc(100% - 27px - 8px)" class="mt-1 d-flex flex-row flex-wrap align-content-space-between">
                            
                            <v-btn
                              height="36"
                              color="btn_bg"
                              class="mt-auto px-0"
                              elevation="0"
                              outlined
                              rounded
                              small
                              width="100%"
                              @click="saveGrid"
                            >
                              <div class="font-weight-bold content--text">
                                {{ `${$t('setupComplete')}` }}
                              </div>
                            </v-btn>
                          </v-sheet>
                        </v-col>
                      </v-sheet>

                      
           
                    </v-row>
                  </template>
                </v-sheet>
              </v-card>
            </v-col>
          </v-row>
          <span class="cctv-roi-manage-contents-mobile">해당 화면은 모바일 환경에서 지원되지 않습니다.</span>
        </v-sheet>
      </v-row>
    </v-container>
  </template>
  
  <script>
  
  import { getUserCd } from '@/utils/token'
  import { getRoiList, getImage } from '@/api/realTimeVideoSafetyManagement/safetyMonitoringZoneManage.js'
  import { getExtension } from '@/utils/common.js'
  import { saveGrid, getInitialImage, pointListView, saveSafetyGrid, loadSafetyGrid } from '@/api/realTimeVideoSafetyManagement/safetyCheckGridManage.js'
  import { adjustGridSize, updateSortDirection } from '@/api/realTimeVideoSafetyManagement/InventoryCheckGridManage.js'
  import { DxFileUploader } from 'devextreme-vue/file-uploader'
  import notify from 'devextreme/ui/notify'

  import baseview from '@/views/base/baseview.vue'
  export default {
    mixins: [baseview],
    name: 'SafetyCheckGridManage',
    components: {
      DxFileUploader
    },
    data() {
      return {
        title: this.$t('safetyCheckGridManage'),
        selected: null,
        selectedItem: {},
        setMode: '0',
        sortDirection: 'up',
        setGridOnOffmode: true, //true: on, false: off
        gridUnit: 3.5, 
        list: [],
        gridPointList: [],
        redoList: [],
        standardGridCoordIsDisable: true, 
        manualControlButtonFirst: [
          { id: 'undo', text: '되돌리기', icon: 'mdi-undo', isDisable: () => this.gridPointList.length == 0 || this.sortDirection != 'up', onClick: () => this.undo() }, 
          { id: 'redo', text: '다시실행', icon: 'mdi-redo', isDisable: () => this.redoList.length == 0 || this.sortDirection != 'up', onClick: () => this.redo() },
          // { id: 'image', text: '테스트 이미지 로드', icon: 'mdi-circle', isDisable: () => false, onClick: () => this.testImage(true) },
          { id: 'takeImage', text: '이미지 가져오기', icon: 'mdi-upload', isDisable: () => false, onClick: () => this.uploadImage(true) },
        ],
        manualControlButtonSecond: [
          { id: 'reset', text: 'reset', icon: 'mdi-refresh', isDisable: () => this.gridPointList.length == 0, onClick: () => this.loadRawImage() },
        ],
        autoControlButtonFirst: [
          { id: 'setGridOnOff', text: '기준격자설정on', icon: 'mdi-cog', isDisable: () => false , onClick: () => this.setGridOnOff() },
          // { id: 'image', text: '테스트 이미지 로드', icon: 'mdi-circle', isDisable: () => false || !this.setGridOnOffmode, onClick: () => this.testImage(true) },///
          { id: 'takeImage', text: '이미지 가져오기', icon: 'mdi-upload', isDisable: () => false || !this.setGridOnOffmode, onClick: () => this.uploadImage(true) },
        ],
        autoControlButtonFirst1: [
          { id: 'upExtend', text: 'extendUp', icon: 'mdi-arrow-up-bold', isDisable: () => this.selectedItem.initial_coordinates.length == 0 || this.setGridOnOffmode, onClick: () => this.adjustSize('up_extend') },
          { id: 'downExtend', text: 'extendDown', icon: 'mdi-arrow-down-bold', isDisable: () => this.selectedItem.initial_coordinates.length == 0 || this.setGridOnOffmode, onClick: () => this.adjustSize('down_extend') },
          { id: 'leftExtend', text: 'extendLeft', icon: 'mdi-arrow-left-bold', isDisable: () => this.selectedItem.initial_coordinates.length == 0 || this.setGridOnOffmode, onClick: () => this.adjustSize('left_extend') },
          { id: 'rightExtend', text: 'extendRight', icon: 'mdi-arrow-right-bold', isDisable: () => this.selectedItem.initial_coordinates.length == 0 || this.setGridOnOffmode, onClick: () => this.adjustSize('right_extend') },
        ],
        autoControlButtonSecond: [
          { id: 'undo', text: '되돌리기', icon: 'mdi-undo', isDisable: () => this.gridPointList.length == 0 || this.sortDirection != 'up' || !this.setGridOnOffmode, onClick: () => this.undo() }, 
          { id: 'redo', text: '다시실행', icon: 'mdi-redo', isDisable: () => this.redoList.length == 0 || this.sortDirection != 'up' || !this.setGridOnOffmode, onClick: () => this.redo() },
          { id: 'reset', text: 'reset', icon: 'mdi-refresh', isDisable: () => this.gridPointList.length == 0 || !this.setGridOnOffmode, onClick: () => this.loadRawImage() },
        ],
        autoControlButtonSecond1: [
          { id: 'downShrink', text: '위로 축소', icon: 'mdi-arrow-down-bold-outline', isDisable: () => this.selectedItem.initial_coordinates.length == 0 || this.setGridOnOffmode, onClick: () => this.adjustSize('up_shrink') },
          { id: 'upShrink', text: '아래로 축소', icon: 'mdi-arrow-up-bold-outline', isDisable: () => this.selectedItem.initial_coordinates.length == 0 || this.setGridOnOffmode, onClick: () => this.adjustSize('down_shrink') },
          { id: 'rightShrink', text: '왼쪽으로 축소', icon: 'mdi-arrow-right-bold-outline', isDisable: () => this.selectedItem.initial_coordinates.length == 0 || this.setGridOnOffmode, onClick: () => this.adjustSize('left_shrink') },
          { id: 'leftShrink', text: '오른쪽으로 축소', icon: 'mdi-arrow-left-bold-outline', isDisable: () => this.selectedItem.initial_coordinates.length == 0 || this.setGridOnOffmode, onClick: () => this.adjustSize('right_shrink') },
        ],
        scaleButton: [
          { id: 'scaleMinus', text: '', icon: 'mdi-minus', isDisable: () => this.scaleFactor == this.scaleMin, onClick: () => this.scaleFactor -= 1 },
          { id: 'scalePlus', text: '', icon: 'mdi-plus', isDisable: () => this.scaleFactor >= this.scaleMax, onClick: () => this.scaleFactor += 1 },
        ],
        sortDirectionButton: [
          { id: 'up', text: 'stadardUp' },
          { id: 'down', text: 'standardDown' },
          { id: 'left', text: 'stadardLeft' },
          { id: 'right', text: 'stadardRight' },
        ],
        setModeButton: [
          { id: '0', text: 'mode0' },
          { id: '1', text: 'mode1' }
        ],
        gridUnitButton: [
          { id: '3.5', text: '3.5x3.5m'},
        ],
        isHovering: false,
        isLoading: true,
        configKonva: {
          width: 0,
          height: 0,
        },
        scaleWidth: 0,
        scaleHeight: 0,
        imageRatio: 16/9,
        isScaleFactor: false,
        //scaleFactor default =  10
        scaleFactor: 3,
        scaleMax: 20,
        scaleMin: 1,
        cctvImg: null,
        inputWidth: 900,
        inputHeight: 600,
        originalWidth: 0, // 이미지 원본 너비
        originalHeight: 0, // 이미지 원본 높이
        use_click: true,
        clickArea: {x: null ,y: null},
        image_base64: null,

        accept: 'image/*',
        allowedFileExtensions: ['jpg', 'jpeg', 'gif', 'png'],
      }
    },
    computed: {
    },
    async mounted() {
      await this.onMounted()
      this.selectedItem.initial_coordinates = []
    },
    watch: {
    },
    methods: {
      onMounted() {
        getRoiList()
          .then(res => {
            this.list = res.list.map(el => {
              const { model_list, ...rest } = el
              return {
                ...rest,
              }
            })
            if(this.list.length !== 0) {
              //Load API있을경우 수정 필요
              this.selected = this.list[0].cctv_id
              if(this.selected == null) {
                this.selected = this.list[0].cctv_id
              } else {
                this. selectedItem.cctv_id = this.list[0].cctv_id
              }
              //이미지 로드
              this.loadImage()
            }
          })
      },
      //기준격자검출 : 격자 조정(확장 및 축소)
      async adjustSize(size) {
        const param = {
          initial_coordinates: this.selectedItem.initial_coordinates,
          sort_direction: this.selectedItem.sortDirection,
          unique_id: this.selectedItem.unique_id,
          operations: [[size, 1]]
        }
        await adjustGridSize(param).then(async res => {
          this.selectedItem.initial_coordinates = res.updated_coordinates
          this.drawImage(res.image_base64)
        })
        .catch(el => {
          if(el.response.data.message == "Cannot shrink below one row." || el.response.data.message == "Cannot shrink below one column." ) {
            this.$vToastify.error({ body: this.$t('errorToastMsg') + ': ' + this.$t('기준 격자를 지울 수  없습니다') })
          }
        })
      },
      setGridOnOff(){
        //격자 생성 여부 확인인
        if(this.gridPointList.length != 4) {
            this.vToastify(
            this.$t('격자가 4개의 점으로 설정완료 되어야 off(확장축소)모드로 변경 가능합니다.'),
            'warn',
            current => {
              
            }, null, true)
 
          return
          }

        this.setGridOnOffmode = !this.setGridOnOffmode
        //버튼이름 변경
        if(this.setGridOnOffmode){
          this.autoControlButtonFirst[0].text = '기준격자설정on'
        }else{
          this.autoControlButtonFirst[0].text = '기준격자설정off'
        }
      },
      onCCTV(param) {
        this.selected = param.cctv_id
        this.selectedItem = param
        this.loadImage()
      },
      onMouseEnter() {
        this.isHovering = true
      },
      onMouseLeave() {
        this.isHovering = false
      },
      onWheel(event) {
        if (event.ctrlKey) {
          event.preventDefault()
          if (event.deltaY < 0 && this.scaleFactor < this.scaleMax) {
            this.scaleFactor++
          } else if (event.deltaY > 0 && this.scaleFactor > this.scaleMin) {
            this.scaleFactor--
          }
        }
      },
      createImg(imgParam) {
        const img = new Image()
        img.src = imgParam
        img.onload = () => {
          this.cctvImg = img
          this.originalWidth = img.width
          this.originalHeight = img.height
          if (this.isScaleFactor) {
            this.scaleWidth = img.width * this.scaleFactor
            this.scaleHeight = img.height * this.scaleFactor
          } else {
            this.scaleWidth = this.inputWidth
            this.scaleHeight = this.inputHeight
          }
          this.configKonva.width = this.scaleWidth
          this.configKonva.height = this.scaleHeight
        }
      },


      drawImage(image) {
        if(image) {
          const byteCharacters = atob(image)
          const byteNumbers = new Array(byteCharacters.length).fill().map((_, i) => byteCharacters.charCodeAt(i))
          const byteArray = new Uint8Array(byteNumbers)
          const blob =  new Blob([byteArray], { type: 'image/jpeg' }) // Blob 생성
          this.createImg(URL.createObjectURL(blob)) // 이미지 표시 함수 호출
        }
